type Animal interface {
    Speak() string
    Name()  string
}

type Dog struct{ name string }

func (d Dog) Speak() string { return "Woof!" }
func (d Dog) Name()  string { return d.name }

// Dog implicitly satisfies Animal — no declaration needed

