public String readFile(String path) throws IOException {
    try (BufferedReader r = new BufferedReader(
            new FileReader(path))) {
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = r.readLine()) != null)
            sb.append(line).append('
');
        return sb.toString();
    }
}

